
"use client"

import { useState, useEffect, useMemo, useRef } from "react";
import dynamic from "next/dynamic";
import { useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import {
  Zap, Loader2, Navigation, Timer, Flag, Trophy, MapPin, Star, Clock, Play, Target, X, Gauge, ShieldAlert, Radio, StopCircle, ChevronRight, Waves, Flame, Map, AlertTriangle
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking } from "@/firebase";
import { doc, collection, query, where, getCountFromServer } from "firebase/firestore";
import { useDriving, RunMode } from "@/context/driving-context";
import { RenderCarIcon } from "@/components/icons/car-icons";
import { reverseGeocode } from "@/services/navigation/geocodingService";
import { ManeuverIcon } from "@/components/navigation/maneuver-icon";

const RouteMap = dynamic(() => import("@/components/telemetry/route-map"), {
  ssr: false,
  loading: () => (
    <div className="w-full h-full flex items-center justify-center bg-zinc-900/50 rounded-3xl min-h-[160px]">
      <div className="flex flex-col items-center gap-2">
        <Loader2 className="w-6 h-6 animate-spin text-accent" />
        <span className="text-[8px] font-black uppercase tracking-widest text-muted-foreground">Duke ngarkuar hartën...</span>
      </div>
    </div>
  )
});

type ReportType = 'Radar' | 'Polici' | 'Kontrollë';
type CockpitMode = 'eco' | 'drag' | 'nav';

export default function DashboardPage() {
  const router = useRouter();
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const {
    speed, isDriving, peakSpeed, tripTime, tripDistance, hasGps,
    currentCoords, routePoints, telemetry, startTime, heading,
    runMode, dragTime, isDragFinished, isDragActive, isNavigating, currentStep, currentRoadName, distanceToNextStep, routeData, countdown, isJumpStart,
    setRunMode, startTrip, stopTrip, resetTrip, requestWakeLock, clearNavigation
  } = useDriving();

  const [mounted, setMounted] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [cityRank, setCityRank] = useState<number | null>(null);
  const [kosovoRank, setKosovoRank] = useState<number | null>(null);
  const [isRankingLoading, setIsRankingLoading] = useState(false);
  const [hasRankingData, setHasRankingData] = useState(false);
  const [liveDragTimer, setLiveDragTimer] = useState(0);
  
  const requestRef = useRef<number>();
  const startTimeRef = useRef<number>();

  const { toast } = useToast();

  const cockpitMode = useMemo((): CockpitMode => {
    if (isNavigating) return 'nav';
    if (runMode !== 'free') return 'drag';
    return 'eco';
  }, [isNavigating, runMode]);

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || isUserLoading || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  // HIGH PRECISION LIVE TIMER
  useEffect(() => {
    const animate = () => {
      if (startTimeRef.current) {
        setLiveDragTimer((performance.now() - startTimeRef.current) / 1000);
      }
      requestRef.current = requestAnimationFrame(animate);
    };

    if (isDragActive) {
      startTimeRef.current = performance.now();
      requestRef.current = requestAnimationFrame(animate);
    } else {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      startTimeRef.current = undefined;
      setLiveDragTimer(0);
    }
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [isDragActive]);

  const isWaitingForStart = isDriving && !isDragActive && !isDragFinished && 
    (runMode === '0-60' || runMode === '0-100' || runMode === '1/4mile') && !isJumpStart;

  const calculateRanks = async () => {
    if (!db || !profile) return;
    setIsRankingLoading(true);
    setCityRank(null);
    setKosovoRank(null);
    setHasRankingData(false);

    try {
      const publicRunsCol = collection(db, "public_runs");
      let kosovoQuery;
      let cityQuery;

      const runTypeLabel = runMode === 'free' ? 'Top Speed' : 
                          runMode === '0-60' ? '0-60' :
                          runMode === '0-100' ? '0-100' : 
                          runMode === '100-200' ? '100-200' : '1/4 Mile';
      const val = (runMode === 'free' || !dragTime) ? peakSpeed : dragTime;

      if (!val || val <= 0) {
        setHasRankingData(false);
        setIsRankingLoading(false);
        return;
      }

      setHasRankingData(true);

      if (runMode === 'free') {
        kosovoQuery = query(publicRunsCol, where("runType", "==", "Top Speed"), where("peakSpeedKmH", ">", val));
        if (profile.city) {
          cityQuery = query(publicRunsCol, where("city", "==", profile.city), where("runType", "==", "Top Speed"), where("peakSpeedKmH", ">", val));
        }
      } else {
        kosovoQuery = query(publicRunsCol, where("runType", "==", runTypeLabel), where("dragTime", "<", val));
        if (profile.city) {
          cityQuery = query(publicRunsCol, where("city", "==", profile.city), where("runType", "==", runTypeLabel), where("dragTime", "<", val));
        }
      }

      const [kosovoSnapshot, citySnapshot] = await Promise.all([
        getCountFromServer(kosovoQuery).catch(() => null),
        cityQuery ? getCountFromServer(cityQuery).catch(() => null) : Promise.resolve(null)
      ]);

      if (kosovoSnapshot) {
        setKosovoRank(kosovoSnapshot.data().count + 1);
      }
      if (citySnapshot) {
        setCityRank(citySnapshot.data().count + 1);
      }
    } catch (e: any) {
      console.error("Ranking failed:", e);
    } finally {
      setIsRankingLoading(false);
    }
  };

  // AUTO TRIGGER SUMMARY WHEN FINISHED
  useEffect(() => {
    if (isDragFinished && mounted && !showSummary) {
      setShowSummary(true);
      calculateRanks();
      // Stop trip after a small delay to allow the summary to be the focus
      setTimeout(() => stopTrip(), 1000);
    }
  }, [isDragFinished, mounted]);

  useEffect(() => {
    if (isJumpStart) {
      toast({
        variant: "destructive",
        title: "JUMP START!",
        description: "U nisët përpara se të ndizej drita e gjelbër. Rezultati është i pavlefshëm.",
      });
    }
  }, [isJumpStart]);

  const handleStartMission = () => {
    if (runMode === '0-60' || runMode === '0-100' || runMode === '1/4mile') {
      if (speed > 0) {
        toast({ variant: "destructive", title: "GABIM", description: "Makina duhet të jetë në 0 km/h për të filluar testin." });
        return;
      }
    }
    startTrip();
    requestWakeLock();
  };

  const handleStopMission = () => {
    if (!isJumpStart && (isDragFinished || runMode === 'free')) {
      setShowSummary(true);
      calculateRanks();
    } else {
      resetTrip();
    }
    stopTrip();
  };

  const formatTime = (seconds: number) => {
    const min = Math.floor(seconds / 60);
    const sec = (seconds % 60).toFixed(2);
    return `${min}m ${sec}s`;
  };

  const handleSaveRun = () => {
    if (!user?.uid || !db || !profile) return;
    setIsSaving(true);
    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      profileIcon: profile.profileIcon,
      city: profile.city || "Kosovë",
      runType: runMode === 'free' ? 'Top Speed' : 
               runMode === '0-60' ? '0-60' :
               runMode === '0-100' ? '0-100' : 
               runMode === '100-200' ? '100-200' : '1/4 Mile',
      startTime: startTime?.toISOString() || new Date().toISOString(),
      endTime: new Date().toISOString(),
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      dragTime: dragTime,
      telemetry: telemetry,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      carProfileId: "primary"
    };

    const userRunsCol = collection(db, "users", user.uid, "runs");
    addDocumentNonBlocking(userRunsCol, runData);
    const publicRunsCol = collection(db, "public_runs");
    addDocumentNonBlocking(publicRunsCol, runData);

    toast({ title: "Ruajtur", description: "Të dhënat u sinkronizuan." });
    setIsSaving(false);
    setShowSummary(false);
    resetTrip();
    setCityRank(null);
    setKosovoRank(null);
    setHasRankingData(false);
  };

  const rpm = useMemo(() => {
    if (speed === 0) return 800;
    const gear = Math.floor(speed / 60) + 1;
    const speedInGear = speed % 60;
    const baseRpm = 1200 + (gear * 100);
    const calculated = baseRpm + (speedInGear * 110);
    return Math.min(Math.floor(calculated), 8000);
  }, [speed]);

  const handleQuickReport = async (type: ReportType) => {
    if (!db || !currentCoords || !user?.uid) {
      toast({ variant: "destructive", title: "Gabim", description: "GPS kërkohet." });
      return;
    }
    const { road, city } = await reverseGeocode(currentCoords.lat, currentCoords.lng);
    const reportsCol = collection(db, "radar_reports");
    addDocumentNonBlocking(reportsCol, {
      type, lat: currentCoords.lat, lng: currentCoords.lng, location: road, city: city,
      createdAt: new Date().toISOString(), userId: user?.uid
    });
    toast({ title: "Raportuar Live!", description: `${type} në ${road}, ${city}.` });
  };

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-black flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>;

  const getThemeColor = () => {
    if (cockpitMode === 'drag') return 'text-red-500';
    if (cockpitMode === 'nav') return 'text-yellow-500';
    return 'text-accent';
  };

  const getThemeBg = () => {
    if (cockpitMode === 'drag') return 'bg-red-500';
    if (cockpitMode === 'nav') return 'bg-yellow-500';
    return 'bg-accent';
  };

  const getDragStatusLabel = () => {
    if (isJumpStart) return "JUMP START!";
    if (!isDriving) return "READY";
    if (isDragFinished) return "FINISHED";
    if (isDragActive) return "RECORDING...";
    if (runMode === '100-200' && speed < 100) return "WAITING FOR 100 KMH";
    if ((runMode === '0-60' || runMode === '0-100' || runMode === '1/4mile') && speed === 0) return "WAITING FOR GREEN";
    return "ACTIVE";
  };

  return (
    <div className="flex flex-col min-h-full bg-black text-foreground pb-24 overflow-x-hidden safe-top relative no-scrollbar">
      {/* Header Info */}
      <div className="p-5 space-y-4 z-20 shrink-0 apple-slide-up">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
             <div className="w-10 h-10 rounded-2xl bg-zinc-900/50 border border-white/5 flex items-center justify-center shadow-lg">
                <RenderCarIcon type={profile?.profileIcon} className={cn("w-5 h-5", getThemeColor())} />
             </div>
             <div>
                <h1 className="text-[10px] font-black uppercase tracking-tight text-white">{profile?.username || "SHOFER"}</h1>
                <div className="flex items-center gap-1.5 mt-0.5">
                  <div className={cn("w-1 h-1 rounded-full", (isDriving || isNavigating) ? getThemeBg() + " animate-pulse" : "bg-zinc-700")} />
                  <span className="text-[7px] font-black uppercase text-muted-foreground tracking-widest">
                    {isNavigating ? "NAVIGIM AKTIV" : runMode !== 'free' ? "DRAG MODE ON" : "TOP SPEED MODE"}
                  </span>
                </div>
             </div>
          </div>
          <Badge variant="outline" className="text-[7px] font-black uppercase border-white/5 text-muted-foreground bg-white/5 py-1 px-3 tracking-widest rounded-lg">
            {hasGps ? "SIGNAL OK" : "SEARCHING GPS..."}
          </Badge>
        </div>

        <div className="grid grid-cols-3 gap-2.5 stagger-1 apple-slide-up">
          {[
            { id: 'Radar', label: 'RADAR', emoji: '🚨', color: 'red' },
            { id: 'Polici', label: 'POLICI', emoji: '🚔', color: 'blue' },
            { id: 'Kontrollë', label: 'KONTROLL', emoji: '🚗', color: 'zinc' }
          ].map((item) => (
            <Button
              key={item.id}
              onClick={() => handleQuickReport(item.id as ReportType)}
              className={cn(
                "h-12 flex flex-col items-center justify-center gap-0.5 rounded-xl border bg-white/5 border-white/5 transition-all active:scale-95",
                item.color === 'red' && "text-red-500 hover:border-red-500/30",
                item.color === 'blue' && "text-blue-400 hover:border-blue-400/30",
                item.color === 'zinc' && "text-zinc-400 hover:border-zinc-400/30"
              )}
            >
              <span className="text-sm">{item.emoji}</span>
              <span className="text-[7px] font-black uppercase tracking-widest">{item.label}</span>
            </Button>
          ))}
        </div>
      </div>

      {/* Interaction Area */}
      <div className="flex-1 flex flex-col items-center justify-center relative px-6 py-2">
        {isNavigating && (
          <div className="w-full max-w-[360px] mb-8 stagger-1 apple-slide-up">
            <Card className="bg-zinc-950/90 backdrop-blur-3xl p-5 rounded-[2.5rem] border-yellow-500/20 shadow-2xl">
              <div className="flex items-center gap-5">
                <div className="w-12 h-12 bg-yellow-500/10 rounded-2xl flex items-center justify-center shrink-0 border border-yellow-500/20">
                  <ManeuverIcon
                    type={currentStep?.type}
                    modifier={currentStep?.modifier}
                    className="w-7 h-7 text-yellow-500"
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <h2 className="text-sm font-black text-white leading-tight uppercase tracking-tight">
                    {currentStep?.instruction || "Vazhdoni drejt"}
                  </h2>
                  <p className="text-[8px] font-black text-white/40 uppercase tracking-widest mt-1">
                    {distanceToNextStep >= 1000 ? `${(distanceToNextStep / 1000).toFixed(1)} km` : `${distanceToNextStep} m`} • {currentRoadName}
                  </p>
                </div>
              </div>
            </Card>
          </div>
        )}

        {/* Mode Selector */}
        <div className="w-full max-w-[300px] mb-8 z-20 apple-scale-in">
          <div className="bg-zinc-900/50 backdrop-blur-3xl p-1.5 rounded-2xl border border-white/5 flex gap-1.5">
            <button
              onClick={() => { clearNavigation(); setRunMode('free'); }}
              className={cn(
                "flex-1 h-10 flex items-center justify-center gap-2 rounded-xl transition-all font-black text-[8px] uppercase tracking-widest",
                cockpitMode === 'eco' ? "bg-accent text-background shadow-lg shadow-accent/20" : "text-muted-foreground hover:bg-white/5"
              )}
            >
              <Zap className="w-3 h-3" /> TOP SPEED
            </button>
            <button
              onClick={() => { clearNavigation(); setRunMode('0-60'); }}
              className={cn(
                "flex-1 h-10 flex items-center justify-center gap-2 rounded-xl transition-all font-black text-[8px] uppercase tracking-widest",
                cockpitMode === 'drag' ? "bg-red-600 text-white shadow-lg shadow-red-600/20" : "text-muted-foreground hover:bg-white/5"
              )}
            >
              <Flame className="w-3 h-3" /> DRAG
            </button>
            <button
              onClick={() => { router.push('/map'); }}
              className={cn(
                "flex-1 h-10 flex items-center justify-center gap-2 rounded-xl transition-all font-black text-[8px] uppercase tracking-widest",
                cockpitMode === 'nav' ? "bg-yellow-600 text-white shadow-lg shadow-yellow-600/20" : "text-muted-foreground hover:bg-white/5"
              )}
            >
              <Map className="w-3 h-3" /> NAV
            </button>
          </div>
        </div>

        {/* Drag Specific Selection (Only if in Drag Mode) */}
        {cockpitMode === 'drag' && (
          <div className="w-full max-w-[280px] mb-6 animate-in slide-in-from-top-4 duration-500">
            <div className="grid grid-cols-4 gap-1.5 bg-zinc-900/30 p-1 rounded-xl border border-white/5">
              {[
                { id: '0-60', label: '0-60' },
                { id: '0-100', label: '0-100' },
                { id: '100-200', label: '100-200' },
                { id: '1/4mile', label: '1/4 MILE' }
              ].map((m) => (
                <button
                  key={m.id}
                  onClick={() => !isDriving && setRunMode(m.id as RunMode)}
                  className={cn(
                    "h-8 rounded-lg text-[7px] font-black uppercase tracking-widest transition-all",
                    runMode === m.id ? "bg-red-500/20 text-red-500 border border-red-500/30" : "text-zinc-500 hover:bg-white/5"
                  )}
                >
                  {m.label}
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Dynamic Gauge */}
        <div className={cn(
          "relative flex items-center justify-center mx-auto mb-6 transition-all duration-700 apple-scale-in",
          "w-full aspect-square max-w-[340px]"
        )}>
          {/* Map Overlay for Nav Mode */}
          {cockpitMode === 'nav' && routeData && (
            <div className="absolute inset-4 rounded-full overflow-hidden border border-yellow-500/20 shadow-inner">
               <RouteMap points={routeData.coordinates} userLocation={currentCoords} heading={heading} />
               <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-transparent to-transparent pointer-events-none" />
            </div>
          )}

          <svg viewBox="0 0 400 400" className="w-full h-full transform -rotate-90 absolute inset-0">
            <circle cx="200" cy="200" r="180" stroke="currentColor" strokeWidth="1" fill="transparent" className="text-white/[0.03]" />
            <circle
              cx="200" cy="200" r="180"
              stroke="currentColor" strokeWidth="4"
              fill="transparent"
              strokeDasharray={2 * Math.PI * 180}
              style={{
                strokeDashoffset: (2 * Math.PI * 180) - (rpm / 8000) * (2 * Math.PI * 180),
                transition: 'stroke-dashoffset 0.1s cubic-bezier(0.2, 0.8, 0.2, 1)'
              }}
              className={cn("transition-all",
                cockpitMode === 'drag' ? (rpm > 7000 ? "text-red-500 drop-shadow-[0_0_10px_rgba(239,68,68,0.5)]" : "text-red-500/40") :
                cockpitMode === 'nav' ? "text-yellow-500/50" :
                "text-accent/50"
              )}
            />
            {/* Speed Arc */}
            <circle
              cx="200" cy="200" r="165"
              stroke="currentColor" strokeWidth="8"
              fill="transparent"
              strokeDasharray={2 * Math.PI * 165}
              style={{
                strokeDashoffset: (2 * Math.PI * 165) - (Math.min(speed, 280) / 280) * (2 * Math.PI * 165),
                transition: 'stroke-dashoffset 0.15s cubic-bezier(0.2, 0.8, 0.2, 1)'
              }}
              className={cn("transition-all",
                cockpitMode === 'drag' ? "text-red-500" :
                cockpitMode === 'nav' ? "text-yellow-500" :
                "text-accent"
              )}
            />
          </svg>

          <div className={cn(
            "z-20 flex flex-col items-center drop-shadow-2xl transition-all duration-500",
            cockpitMode === 'nav' ? "mt-24" : "mt-0"
          )}>
            {isDragActive && (
              <Badge className="bg-red-600 text-white font-black text-[8px] px-3 py-1 mb-2 animate-pulse rounded-full">TESTING ACTIVE</Badge>
            )}
            {isJumpStart && (
              <Badge className="bg-red-600 text-white font-black text-[8px] px-3 py-1 mb-2 rounded-full flex items-center gap-1">
                <AlertTriangle className="w-3 h-3" /> JUMP START
              </Badge>
            )}
            <span className={cn(
              "font-black tracking-tighter leading-none tabular-nums text-white transition-all duration-75",
              cockpitMode === 'nav' ? (speed > 99 ? "text-5xl" : "text-6xl") : (speed > 99 ? "text-7xl" : "text-8xl"),
              isJumpStart && "text-red-500"
            )}>
              {speed}
            </span>
            <span className={cn(
              "font-black uppercase tracking-[0.4em] text-[10px] mt-1",
              cockpitMode === 'drag' ? "text-red-500" : cockpitMode === 'nav' ? "text-yellow-500" : "text-accent"
            )}>KM/H</span>

            {cockpitMode === 'drag' && (
               <div className="mt-4 flex flex-col items-center">
                 {isWaitingForStart && (
                    <div className="flex items-center gap-3 mb-2 apple-scale-in">
                      {[1, 2, 3, 4, 5].map((i) => (
                        <div 
                          key={i}
                          className={cn(
                            "w-5 h-5 rounded-full border-2 transition-all duration-300 shadow-xl",
                            countdown >= i 
                              ? "bg-red-600 border-red-400 shadow-[0_0_12px_rgba(220,38,38,0.8)]" 
                              : "bg-zinc-900 border-white/5"
                          )}
                        />
                      ))}
                      <div 
                        className={cn(
                          "w-7 h-7 rounded-full border-2 transition-all duration-500 shadow-2xl",
                          countdown >= 6 
                            ? "bg-green-500 border-green-300 shadow-[0_0_20px_rgba(34,197,94,1)] scale-110" 
                            : "bg-zinc-900 border-white/5"
                        )}
                      />
                    </div>
                 )}
                 <span className="text-[8px] font-black text-white/30 tracking-widest uppercase">{getDragStatusLabel()}</span>
                 <span className="text-sm font-black text-red-500">{(rpm/1000).toFixed(1)}</span>
               </div>
            )}
          </div>
        </div>

        {/* Stats Grid - Dragy Style */}
        {cockpitMode === 'drag' ? (
          <div className="grid grid-cols-2 gap-4 w-full max-w-[320px] z-20 mb-8 stagger-2 apple-slide-up bg-zinc-900/20 p-4 rounded-[2rem] border border-white/5">
             <div className="flex flex-col items-center border-r border-white/5">
               <span className="text-[7px] font-black text-zinc-500 uppercase tracking-widest mb-1">G-FORCE</span>
               <span className="text-xl font-black text-white italic">{(speed > 0 ? (1.1 + (speed/100)).toFixed(2) : "0.00")} G</span>
             </div>
             <div className="flex flex-col items-center">
               <span className="text-[7px] font-black text-zinc-500 uppercase tracking-widest mb-1">{isDragActive ? "CURRENT TIME" : "BEST TIME"}</span>
               <span className="text-xl font-black text-red-500 italic">
                 {isDragActive ? liveDragTimer.toFixed(2) + 's' : dragTime ? dragTime.toFixed(2) + 's' : '0.00s'}
               </span>
             </div>
             <div className="flex flex-col items-center border-r border-white/5 pt-4">
               <span className="text-[7px] font-black text-zinc-500 uppercase tracking-widest mb-1">ALTITUDE</span>
               <span className="text-sm font-black text-white">432m</span>
             </div>
             <div className="flex flex-col items-center pt-4">
               <span className="text-[7px] font-black text-zinc-500 uppercase tracking-widest mb-1">SLOPE</span>
               <span className="text-sm font-black text-green-500">-0.2%</span>
             </div>
          </div>
        ) : (
          <div className="grid grid-cols-2 gap-3 w-full max-w-[280px] z-20 mb-8 stagger-2 apple-slide-up">
             <div className="bg-zinc-900/40 border border-white/5 p-4 rounded-3xl flex flex-col items-center shadow-xl">
               <span className="text-[7px] font-black text-muted-foreground uppercase tracking-[0.2em] mb-1">DISTANCA</span>
               <span className="text-sm font-black text-white">{(tripDistance / 1000).toFixed(2)} KM</span>
             </div>
             <div className="bg-zinc-900/40 border border-white/5 p-4 rounded-3xl flex flex-col items-center shadow-xl">
               <span className="text-[7px] font-black text-muted-foreground uppercase tracking-[0.2em] mb-1">SHPEJTËSIA MAX</span>
               <span className={cn("text-sm font-black", getThemeColor())}>{peakSpeed} KM/H</span>
             </div>
          </div>
        )}

        {/* Action Button */}
        <div className="w-full max-w-[280px] space-y-3 stagger-3 apple-slide-up mb-10">
          <Button
            onClick={() => isDriving ? handleStopMission() : handleStartMission()}
            className={cn(
              "w-full h-16 rounded-full font-black text-sm uppercase tracking-widest transition-all shadow-2xl active:scale-95",
              isDriving ? "bg-red-900/40 hover:bg-red-900/60 border border-red-500/30 text-white" :
              cockpitMode === 'drag' ? "bg-red-600 hover:bg-red-700 text-white shadow-red-600/30" :
              cockpitMode === 'nav' ? "bg-yellow-600 hover:bg-yellow-700 text-white shadow-yellow-600/30" :
              "bg-accent hover:bg-accent/80 text-background shadow-accent/30"
            )}
          >
            {isDriving ? "STOP MISSION" : (cockpitMode === 'drag' ? "START DRAG TEST" : "START TOP SPEED")}
          </Button>
        </div>
      </div>

      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="bg-[#0c0c0e] border-white/5 w-[94%] max-w-sm rounded-[2.5rem] p-0 overflow-hidden apple-scale-in max-h-[95vh] flex flex-col">
          <DialogHeader className="sr-only">
            <DialogTitle>DriveRank Summary</DialogTitle>
            <DialogDescription>Overview of your driving performance and rankings.</DialogDescription>
          </DialogHeader>
          <div className="flex-1 overflow-y-auto no-scrollbar p-6 space-y-6">
            <div className="text-center">
              <h2 className="text-2xl font-black text-white tracking-tighter italic">DriveRank</h2>
            </div>

            <div className="flex justify-between px-4">
              <div className="text-center">
                <p className="text-2xl font-black text-white">{(tripDistance / 1000).toFixed(2)} km</p>
                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Distance</p>
              </div>
              <div className="text-center">
                <p className="text-2xl font-black text-white">{formatTime(tripTime)}</p>
                <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest">Total time</p>
              </div>
            </div>

            <Card className="bg-zinc-900/60 border-white/5 p-8 rounded-[2rem] flex flex-col items-center justify-center space-y-4 shadow-2xl relative overflow-hidden">
              <div className="absolute inset-0 bg-gradient-to-br from-accent/5 to-transparent pointer-events-none" />
              <p className="text-[10px] font-black text-muted-foreground uppercase tracking-[0.3em] relative z-10">
                {runMode === 'free' ? 'Top Speed' : runMode.toUpperCase()}
              </p>
              <div className="text-center relative z-10">
                <span className="text-6xl font-black text-white italic">
                  {(runMode === 'free' || !dragTime) ? peakSpeed : dragTime?.toFixed(2)}
                </span>
                <span className="text-xl font-black text-white/50 ml-2 italic">
                  {(runMode === 'free' || !dragTime) ? 'km/h' : 's'}
                </span>
              </div>

              {isRankingLoading ? (
                <div className="flex flex-col items-center gap-2 mt-2">
                   <Loader2 className="w-5 h-5 animate-spin text-accent" />
                   <p className="text-[8px] font-black text-accent uppercase tracking-widest">Duke Kalkuluar...</p>
                </div>
              ) : (
                <div className="flex items-center gap-2 bg-accent/10 px-4 py-2 rounded-xl border border-accent/20 relative z-10">
                  <Trophy className="w-3.5 h-3.5 text-accent" />
                  <p className="text-[10px] font-black text-accent uppercase tracking-wider">
                    {cityRank === 1 || (kosovoRank === 1 && !cityRank) ? (
                      `1st place on ${profile?.city || 'Kosovo'} Today`
                    ) : cityRank ? (
                      `#${cityRank} fastest in ${profile?.city}`
                    ) : kosovoRank ? (
                      `#${kosovoRank} fastest in Kosovë`
                    ) : hasRankingData ? (
                      "New Record Achieved"
                    ) : (
                      "Free Ride Session"
                    )}
                  </p>
                </div>
              )}
            </Card>

            <div className="h-40 w-full rounded-[2rem] overflow-hidden border border-white/5 relative shadow-inner">
               {mounted && showSummary && <RouteMap points={routePoints} />}
            </div>

            <div className="space-y-4 text-center">
              <p className="text-[9px] font-bold text-muted-foreground uppercase tracking-widest">
                {new Date().toLocaleDateString('sq-AL', { month: 'short', day: 'numeric', year: 'numeric' })}, {profile?.city || 'Kosovë'}
              </p>

              <div className="flex flex-col gap-2">
                <Button onClick={handleSaveRun} disabled={isSaving || isRankingLoading} className="w-full h-14 bg-red-600 hover:bg-red-700 text-white rounded-[1.5rem] font-black uppercase text-[11px] tracking-widest shadow-xl transition-all active:scale-95">
                  {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : "RUAJ REZULTATIN"}
                </Button>
                <Button variant="ghost" className="w-full h-10 rounded-xl font-black uppercase text-[9px] text-zinc-600 tracking-widest hover:text-white" onClick={() => { setShowSummary(false); resetTrip(); setCityRank(null); setKosovoRank(null); setHasRankingData(false); }}>
                  FSHIJ RRUGËTIMIN
                </Button>
              </div>
            </div>
          </div>
        </DialogContent>
      </Dialog>
      <BottomNav />
    </div>
  );
}
